// Leverage = reach x severity x recency. Mirrors the companion TS tool.
const NOW = Date.now();
const DAY = 86400000;
const scoredAt = new Date(NOW).toISOString();

// GitHub /issues returns arrays (one per paginated page); flatten whatever n8n handed us.
const raw = [];
for (const it of $input.all()) {
  const j = it.json;
  if (Array.isArray(j)) raw.push(...j);
  else if (j && j.number) raw.push(j);
  else if (j && Array.isArray(j.data)) raw.push(...j.data);
}

const severity = (labels) => {
  const has = (s) => labels.some((l) => (l.name || '').toLowerCase().includes(s));
  if (has('bug') || has('crash') || has('regression')) return 3.0;
  if (has('node/issue') || has('security')) return 2.5;
  if (has('node/improvement') || has('enhancement') || has('feature')) return 1.6;
  if (has('question') || has('docs') || has('documentation')) return 0.8;
  return 1.4;
};

const scored = raw
  .filter((x) => x && x.number && !x.pull_request)
  .map((x) => {
    const labels = x.labels || [];
    const reactions = (x.reactions && x.reactions.total_count) || 0;
    const comments = x.comments || 0;
    const idleDays = Math.max(0, (NOW - Date.parse(x.updated_at)) / DAY);
    const ageDays = Math.max(0, (NOW - Date.parse(x.created_at)) / DAY);
    const reach = 1 + 2 * Math.log1p(reactions) + Math.log1p(comments);
    const recency = Math.exp(-idleDays / 60);
    const sev = severity(labels);
    const leverage = +(reach * sev * recency).toFixed(2);
    const churnRisk = +(reach * sev * Math.log1p(ageDays) * Math.min(1, idleDays / 30)).toFixed(2);
    return {
      number: x.number,
      title: x.title,
      url: x.html_url,
      reactions,
      comments,
      ageDays: Math.round(ageDays),
      idleDays: Math.round(idleDays),
      leverage,
      churnRisk,
      scoredAt,
    };
  });

scored.sort((a, b) => b.leverage - a.leverage);
return scored.slice(0, 25).map((s) => ({ json: s }));
